package core

import (
	"context"
	"testing"
	"time"
)

// TestWorkerPool_TaskExecution verifies that tasks submitted to the pool
// are correctly dispatched, processed by the engine, and results are returned.
func TestWorkerPool_TaskExecution(t *testing.T) {
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	engine := NewMockLlamaEngine()
	defer engine.Close()

	// Initialize worker pool with bounded capacity
	const maxWorkers = 2
	const queueCapacity = 5
	pool := NewWorkerPool(engine, maxWorkers, queueCapacity)
	pool.Start(ctx)
	defer pool.Stop()

	// Submit a task with a structured payload and GBNF grammar request
	respChan := make(chan TaskResult, 1)
	task := Task{
		ID:           "test-task-100",
		Payload:      "Verify local modular tensor execution pipeline.",
		Grammar:      `{"status": "valid"}`,
		ResponseChan: respChan,
	}

	err := pool.Submit(ctx, task)
	if err != nil {
		t.Fatalf("failed to submit valid task to pool: %v", err)
	}

	// Wait for the worker to process the task and write back the response
	select {
	case <-ctx.Done():
		t.Fatal("test execution timed out before response was received")
	case res := <-respChan:
		if res.Error != nil {
			t.Fatalf("unexpected task execution error: %v", res.Error)
		}
		if res.ID != "test-task-100" {
			t.Errorf("expected task ID 'test-task-100', got '%s'", res.ID)
		}

		// Verify response payload structural validity (should be simulated grammar json)
		expectedJSON := `{"category": "world_news", "urgency": "medium", "sentiment": "neutral", "summary": "Simulated extraction for prompt context."}`
		if res.Response.Content != expectedJSON {
			t.Errorf("expected response content '%s', got '%s'", expectedJSON, res.Response.Content)
		}

		if res.Response.TokensPredict <= 0 {
			t.Errorf("expected generated tokens count > 0, got %d", res.Response.TokensPredict)
		}

		if res.Response.Timings.PredictTimeMS <= 0 {
			t.Errorf("expected positive predict latency, got %.2f ms", res.Response.Timings.PredictTimeMS)
		}
	}

	// Verify telemetry metrics reflect execution
	metrics := pool.GetMetrics()
	if metrics.TotalTasks != 1 {
		t.Errorf("expected 1 total task in metrics, got %d", metrics.TotalTasks)
	}
	if metrics.FailedTasks != 0 {
		t.Errorf("expected 0 failed tasks in metrics, got %d", metrics.FailedTasks)
	}
}

// TestWorkerPool_CircuitBreaker verifies that submitting tasks exceeding queue depth
// returns the ErrPoolFull error as part of the graceful degradation / backpressure logic.
func TestWorkerPool_CircuitBreaker(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	engine := NewMockLlamaEngine()
	defer engine.Close()

	// Initialize worker pool with no workers active yet or an extremely small queue capacity
	// to easily saturate the buffer.
	const maxWorkers = 0
	const queueCapacity = 2
	pool := NewWorkerPool(engine, maxWorkers, queueCapacity)
	// We deliberately do not start the pool, meaning tasks will sit in the queue indefinitely.

	// Fill the queue capacity
	for i := 0; i < queueCapacity; i++ {
		task := Task{
			ID:           "fill-task",
			ResponseChan: make(chan TaskResult, 1),
		}
		err := pool.Submit(ctx, task)
		if err != nil {
			t.Fatalf("failed to fill queue at step %d: %v", i, err)
		}
	}

	// Attempting to submit one more task must trigger the circuit breaker
	overflowTask := Task{
		ID:           "overflow-task",
		ResponseChan: make(chan TaskResult, 1),
	}
	err := pool.Submit(ctx, overflowTask)
	if err != ErrPoolFull {
		t.Errorf("expected ErrPoolFull when buffer is saturated, got: %v", err)
	}

	// Verify metrics show filled queue depth
	metrics := pool.GetMetrics()
	if metrics.QueueDepth != queueCapacity {
		t.Errorf("expected queue depth %d, got %d", queueCapacity, metrics.QueueDepth)
	}
}

package core

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"sync"
)

var (
	ErrBotNotFound = errors.New("bot profile not found in orchestrator pool")
)

// BotProfile defines configuration context and rules for specialized local inference bots.
type BotProfile struct {
	ID           string `json:"id"`
	Name         string `json:"name"`
	SystemPrompt string `json:"system_prompt"`
	GrammarPath  string `json:"grammar_path"`
}

// PayloadWrapper matches the standard structured event ingestion payload containing target routing details.
type PayloadWrapper struct {
	BotID   string `json:"bot_id"`
	Content string `json:"content"`
}

// BotPool governs registration and dynamic routing of tasks to context-specific workers.
type BotPool struct {
	mu         sync.RWMutex
	profiles   map[string]BotProfile
	workerPool *WorkerPool
}

// NewBotPool initializes a thread-safe bot orchestrator.
func NewBotPool(wp *WorkerPool) *BotPool {
	return &BotPool{
		profiles:   make(map[string]BotProfile),
		workerPool: wp,
	}
}

// RegisterProfile adds or updates a BotProfile in the routing table.
func (p *BotPool) RegisterProfile(profile BotProfile) error {
	if profile.ID == "" {
		return errors.New("invalid bot profile: ID cannot be empty")
	}

	p.mu.Lock()
	defer p.mu.Unlock()
	p.profiles[profile.ID] = profile
	return nil
}

// GetProfile retrieves a profile from the pool registry.
func (p *BotPool) GetProfile(botID string) (BotProfile, bool) {
	p.mu.RLock()
	defer p.mu.RUnlock()
	profile, exists := p.profiles[botID]
	return profile, exists
}

// Route inspects the task payload, loads specific grammar, maps system prompts, and schedules processing.
func (p *BotPool) Route(ctx context.Context, task Task) error {
	var botID string
	var innerContent string

	// Attempt JSON payload parsing to extract target bot_id and content
	var wrap PayloadWrapper
	if err := json.Unmarshal([]byte(task.Payload), &wrap); err == nil && wrap.BotID != "" {
		botID = wrap.BotID
		innerContent = wrap.Content
	} else {
		// Fallback to default 'aggregator' profile for unstructured payloads
		botID = "aggregator"
		innerContent = task.Payload
	}

	// Fetch target BotProfile
	profile, exists := p.GetProfile(botID)
	if !exists {
		return fmt.Errorf("%w: %s", ErrBotNotFound, botID)
	}

	// Load specialized context-free grammar from profile path
	var grammarContent string
	if profile.GrammarPath != "" {
		content, err := os.ReadFile(profile.GrammarPath)
		if err != nil {
			return fmt.Errorf("failed to read bot grammar file (%s): %w", profile.GrammarPath, err)
		}
		grammarContent = string(content)
	}

	// Re-format task payload to isolate state and inject the system prompt constraints
	formattedPrompt := fmt.Sprintf("System: %s\n\nUser: %s", profile.SystemPrompt, innerContent)

	task.Payload = formattedPrompt
	task.Grammar = grammarContent

	// Enqueue in the bounded worker pool
	return p.workerPool.Submit(ctx, task)
}

