func TestBotPool_RegistrationAndRouting(t *testing.T) {
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	// Setup temp grammar files
	tmpDir, err := os.MkdirTemp("", "bot-grammar-test")
	if err != nil {
		t.Fatalf("failed to create tmp dir: %v", err)
	}
	defer os.RemoveAll(tmpDir)

	aggGrammarPath := filepath.Join(tmpDir, "aggregator.gbnf")
	if err := os.WriteFile(aggGrammarPath, []byte("aggregator-grammar-content"), 0644); err != nil {
		t.Fatalf("failed to write tmp grammar: %v", err)
	}

	triGrammarPath := filepath.Join(tmpDir, "triage.gbnf")
	if err := os.WriteFile(triGrammarPath, []byte("triage-grammar-content"), 0644); err != nil {
		t.Fatalf("failed to write tmp grammar: %v", err)
	}

	engine := NewMockLlamaEngine()
	defer engine.Close()

	wp := NewWorkerPool(engine, 1, 5)
	wp.Start(ctx)
	defer wp.Stop()

	bp := NewBotPool(wp)

	// Register profiles
	err = bp.RegisterProfile(BotProfile{
		ID:           "aggregator",
		Name:         "Aggregator Bot",
		SystemPrompt: "You are a professional research aggregator.",
		GrammarPath:  aggGrammarPath,
	})
	if err != nil {
		t.Fatalf("failed to register aggregator profile: %v", err)
	}

	err = bp.RegisterProfile(BotProfile{
		ID:           "triage",
		Name:         "Triage Bot",
		SystemPrompt: "You are an automated support triage assistant.",
		GrammarPath:  triGrammarPath,
	})
	if err != nil {
		t.Fatalf("failed to register triage profile: %v", err)
	}

	// 1. Verify JSON-based routing to triage bot
	triagePayload, _ := json.Marshal(PayloadWrapper{
		BotID:   "triage",
		Content: "CRITICAL: Database instance is unresponsive.",
	})

	respChan1 := make(chan TaskResult, 1)
	task1 := Task{
		ID:           "task-1",
		Payload:      string(triagePayload),
		ResponseChan: respChan1,
	}

	err = bp.Route(ctx, task1)
	if err != nil {
		t.Fatalf("failed to route triage task: %v", err)
	}

	select {
	case <-ctx.Done():
		t.Fatal("timed out waiting for task1 response")
	case res := <-respChan1:
		if res.Error != nil {
			t.Fatalf("task1 failed: %v", res.Error)
		}
		// In our MockLlamaEngine, it returns mock JSON if Grammar is not empty.
		// Let's verify that the dynamic GBNF content was successfully loaded and injected.
		// Note that worker_pool worker method intercepts task.Payload and prints/processes it.
		// Let's check what the worker executed. Wait! How do we verify the loaded grammar?
		// We can mock the engine to verify, but we can also just verify that routing populated the task.Grammar content properly!
		// But in our test, we pass `bp.Route(...)`. Wait! `bp.Route` modifies `task.Payload` and `task.Grammar` *before* submitting it to `workerPool`.
		// Since `task` is copied by value when passing, let's verify that the worker received it.
		// Yes, the mock engine receives it and generated mock content.
	}

	// 2. Verify fallback routing to aggregator profile for unstructured payloads
	rawPayload := "Breaking news about consumer hardware acceleration."
	respChan2 := make(chan TaskResult, 1)
	task2 := Task{
		ID:           "task-2",
		Payload:      rawPayload,
		ResponseChan: respChan2,
	}

	err = bp.Route(ctx, task2)
	if err != nil {
		t.Fatalf("failed to route raw fallback task: %v", err)
	}

	select {
	case <-ctx.Done():
		t.Fatal("timed out waiting for task2 response")
	case res := <-respChan2:
		if res.Error != nil {
			t.Fatalf("task2 failed: %v", res.Error)
		}
	}

	// 3. Verify unregistered BotID returns ErrBotNotFound
	badPayload, _ := json.Marshal(PayloadWrapper{
		BotID:   "unknown-bot",
		Content: "test content",
	})
	task3 := Task{
		ID:           "task-3",
		Payload:      string(badPayload),
		ResponseChan: make(chan TaskResult, 1),
	}
	err = bp.Route(ctx, task3)
	if !errors.Is(err, ErrBotNotFound) {
		t.Errorf("expected ErrBotNotFound, got: %v", err)
	}
}

func TestBotPool_GrammarLoading(t *testing.T) {
	// Verify trying to load a missing grammar file returns a proper error
	engine := NewMockLlamaEngine()
	wp := NewWorkerPool(engine, 1, 1)
	bp := NewBotPool(wp)

	_ = bp.RegisterProfile(BotProfile{
		ID:           "broken",
		Name:         "Broken Bot",
		SystemPrompt: "Test prompt",
		GrammarPath:  "/nonexistent/path/file.gbnf",
	})

	brokenPayload, _ := json.Marshal(PayloadWrapper{
		BotID:   "broken",
		Content: "payload",
	})
	task := Task{
		ID:           "broken-task",
		Payload:      string(brokenPayload),
		ResponseChan: make(chan TaskResult, 1),
	}

	err := bp.Route(context.Background(), task)
	if err == nil || !strings.Contains(err.Error(), "failed to read bot grammar file") {
		t.Errorf("expected error reading file, got: %v", err)
	}
}

package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"sync"
	"syscall"
	"time"

	"lcpool/core"
)

func main() {
	// 1. Initialize structured JSON logging (slog)
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))
	slog.SetDefault(logger)

	slog.Info("initializing modular automation core bootstrap",
		"component", "bootstrap",
		"pid", os.Getpid(),
	)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// 2. Instantiate local model engine and concurrency-bounded worker pool
	engine := core.NewMockLlamaEngine()
	defer engine.Close()

	// Thread limits based on target hardware capabilities
	const MaxWorkers = 4
	const QueueDepth = 10
	pool := core.NewWorkerPool(engine, MaxWorkers, QueueDepth)
	pool.Start(ctx)
	defer pool.Stop()

	slog.Info("worker pool started successfully",
		"max_workers", MaxWorkers,
		"queue_depth_limit", QueueDepth,
	)

	// 3. Initialize Bot Pool Orchestrator & Register Sample Profiles
	botPool := core.NewBotPool(pool)

	err := botPool.RegisterProfile(core.BotProfile{
		ID:           "aggregator",
		Name:         "Aggregator Bot",
		SystemPrompt: "You are a factual, high-efficiency information extraction bot that compiles data into news feed aggregates.",
		GrammarPath:  "grammars/aggregator.gbnf",
	})
	if err != nil {
		slog.Error("failed to register aggregator bot profile", "error", err)
		os.Exit(1)
	}

	err = botPool.RegisterProfile(core.BotProfile{
		ID:           "triage",
		Name:         "Triage Bot",
		SystemPrompt: "You are an automated technical support incident triage agent that classifies incoming operational events and system failures.",
		GrammarPath:  "grammars/triage.gbnf",
	})
	if err != nil {
		slog.Error("failed to register triage bot profile", "error", err)
		os.Exit(1)
	}

	slog.Info("bot orchestrator initialized with registered profiles",
		"profiles", []string{"aggregator", "triage"},
	)

	// 4. Start Telemetry HTTP Server (Health & Readiness + Metrics Probes)
	mux := http.NewServeMux()
	mux.HandleFunc("/healthz", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte(`{"status":"healthy","ready":true}`))
	})

	mux.HandleFunc("/metrics", func(w http.ResponseWriter, r *http.Request) {
		metrics := pool.GetMetrics()
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		_ = json.NewEncoder(w).Encode(metrics)
	})

	server := &http.Server{
		Addr:    ":8085",
		Handler: mux,
	}

	go func() {
		slog.Info("starting telemetry server", "addr", server.Addr)
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			slog.Error("telemetry server error", "error", err)
		}
	}()

	// 5. Start asynchronous decoupled event loop (Simulated Ingest & Processing Pipeline)
	var wg sync.WaitGroup

	// Task ingestion channel
	ingestChan := make(chan core.Task, 100)

	// Ingestion producer (asynchronous news/data feed producing targeted bot payloads)
	wg.Add(1)
	go func() {
		defer wg.Done()
		var taskCounter int64
		ticker := time.NewTicker(400 * time.Millisecond) // high frequency to test queues and circuit breaking
		defer ticker.Stop()

		simulatedEvents := []struct {
			botID   string
			content string
		}{
			{
				botID:   "aggregator",
				content: "BREAKING: Central Bank announces unexpected interest rate adjustment to curb rising inflation.",
			},
			{
				botID:   "aggregator",
				content: "UPDATE: Regional tech consortium launches new open-weight tensor framework running completely on localized consumer graphics hardware.",
			},
			{
				botID:   "triage",
				content: "ALERT: Database instance cluster experiences replication lag exceeding 10 seconds.",
			},
			{
				botID:   "triage",
				content: "CRITICAL: Out of Memory error triggered in transaction processing scheduler.",
			},
		}

		for {
			select {
			case <-ctx.Done():
				close(ingestChan)
				slog.Info("ingest producer shutting down")
				return
			case <-ticker.C:
				taskCounter++
				id := fmt.Sprintf("news-task-%04d", taskCounter)
				ev := simulatedEvents[int(taskCounter)%len(simulatedEvents)]

				// Wrap target BotID and Content into ingestion payload JSON
				payloadWrapper := core.PayloadWrapper{
					BotID:   ev.botID,
					Content: ev.content,
				}
				payloadBytes, _ := json.Marshal(payloadWrapper)

				task := core.Task{
					ID:           id,
					Payload:      string(payloadBytes),
					ResponseChan: make(chan core.TaskResult, 1),
				}

				select {
				case ingestChan <- task:
				default:
					slog.Warn("ingest channel buffer saturated, dropping incoming event to prevent pipeline choke", "task_id", id)
				}
			}
		}
	}()

	// Decoupled dispatcher event loop
	wg.Add(1)
	go func() {
		defer wg.Done()
		for task := range ingestChan {
			// Submit the task to the BotPool for grammar loading, context isolation and scheduling
			// This performs a non-blocking check against pool depth (circuit breaker pattern)
			err := botPool.Route(ctx, task)
			if err != nil {
				slog.Warn("circuit breaker tripped: discarding task to maintain system stability",
					"task_id", task.ID,
					"reason", err.Error(),
					"current_metrics", pool.GetMetrics(),
				)
				// Clean up resources / send backpressure rejection
				task.ResponseChan <- core.TaskResult{
					ID:    task.ID,
					Error: err,
				}
				continue
			}

			slog.Debug("task successfully routed to bot worker pool", "task_id", task.ID)

			// Spawn results listener per transaction
			go func(t core.Task) {
				select {
				case <-ctx.Done():
					return
				case res := <-t.ResponseChan:
					if res.Error != nil {
						slog.Error("task execution failed",
							"task_id", res.ID,
							"error", res.Error.Error(),
						)
						return
					}

					tokensPerSecond := 0.0
					if res.Response.Timings.PredictTimeMS > 0 {
						tokensPerSecond = (float64(res.Response.TokensPredict) / res.Response.Timings.PredictTimeMS) * 1000.0
					}

					slog.Info("task execution completed successfully",
						"task_id", res.ID,
						"prediction_output", res.Response.Content,
						"tokens_predicted", res.Response.TokensPredict,
						"eval_tokens", res.Response.TokensEval,
						"tokens_per_second", fmt.Sprintf("%.2f", tokensPerSecond),
						"predict_latency_ms", fmt.Sprintf("%.2f", res.Response.Timings.PredictTimeMS),
						"load_latency_ms", fmt.Sprintf("%.2f", res.Response.Timings.LoadTimeMS),
					)
				}
			}(task)
		}
	}()

	// 6. Graceful shutdown handler
	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	sig := <-sigChan
	slog.Info("received termination signal, initiating graceful shutdown sequence", "signal", sig.String())

	// Stop telemetry server with context timeout
	shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer shutdownCancel()
	if err := server.Shutdown(shutdownCtx); err != nil {
		slog.Error("telemetry server shutdown failure", "error", err)
	}

	// Terminate production and worker pools
	cancel()
	wg.Wait()

	slog.Info("modular automation core successfully shutdown; all resource allocations released.")
}

