package core

import (
	"context"
	"math/rand"
	"time"
)

// MockLlamaEngine provides a thread-safe simulation of local tensor execution.
// It uses configured latency approximations to mimic execution graph evaluation.
type MockLlamaEngine struct {
	rng *rand.Rand
}

// NewMockLlamaEngine initializes a new MockLlamaEngine instance.
func NewMockLlamaEngine() *MockLlamaEngine {
	return &MockLlamaEngine{
		rng: rand.New(rand.NewSource(time.Now().UnixNano())),
	}
}

// Predict simulates executing a local GGUF model and enforcing GBNF grammars.
func (e *MockLlamaEngine) Predict(ctx context.Context, req InferenceRequest) (InferenceResponse, error) {
	// Simulate model loading or context setup overhead
	loadStart := time.Now()
	select {
	case <-ctx.Done():
		return InferenceResponse{}, ctx.Err()
	case <-time.After(10 * time.Millisecond):
	}
	loadDuration := time.Since(loadStart)

	// Simulate prompt evaluation (pre-fill phase)
	evalStart := time.Now()
	select {
	case <-ctx.Done():
		return InferenceResponse{}, ctx.Err()
	case <-time.After(30 * time.Millisecond):
	}
	evalDuration := time.Since(evalStart)

	// Simulate generation (predict phase with variable latency matching max token bounds)
	predictStart := time.Now()
	// Let's generate a simulated structured JSON output
	// For news bot, let's pretend to classify a message or extract payload
	var mockContent string
	if req.Grammar != "" {
		mockContent = `{"category": "world_news", "urgency": "medium", "sentiment": "neutral", "summary": "Simulated extraction for prompt context."}`
	} else {
		mockContent = "Simulated free-form response from the core engine execution loop."
	}

	tokensToPredict := 25 + rand.Intn(15)
	if req.MaxTokens > 0 && tokensToPredict > req.MaxTokens {
		tokensToPredict = req.MaxTokens
	}

	// 5ms per token simulation
	tokenGenerationDelay := time.Duration(tokensToPredict*5) * time.Millisecond
	select {
	case <-ctx.Done():
		return InferenceResponse{}, ctx.Err()
	case <-time.After(tokenGenerationDelay):
	}
	predictDuration := time.Since(predictStart)

	return InferenceResponse{
		Content:       mockContent,
		TokensPredict: tokensToPredict,
		TokensEval:    len(req.Prompt) / 4, // Rough approximation
		Timings: PredictTimings{
			LoadTimeMS:       float64(loadDuration.Microseconds()) / 1000.0,
			SampleTimeMS:     0.5 + float64(rand.Intn(200))/100.0,
			PromptEvalTimeMS: float64(evalDuration.Microseconds()) / 1000.0,
			PredictTimeMS:    float64(predictDuration.Microseconds()) / 1000.0,
		},
	}, nil
}

// Close releases any locked weight pages or scratchpad buffers.
func (e *MockLlamaEngine) Close() error {
	return nil
}

// Ensure MockLlamaEngine implements the interface
var _ LlamaEngine = (*MockLlamaEngine)(nil)

package core

import (
	"bytes"
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"time"
)

// PredictTimings tracks runtime performance metrics of a single generation cycle.
type PredictTimings struct {
	LoadTimeMS       float64 `json:"load_time_ms"`
	SampleTimeMS     float64 `json:"sample_time_ms"`
	PromptEvalTimeMS float64 `json:"prompt_eval_time_ms"`
	PredictTimeMS    float64 `json:"predict_time_ms"`
}

// InferenceRequest defines parameters for the tensor execution run.
type InferenceRequest struct {
	Prompt      string  `json:"prompt"`
	Grammar     string  `json:"grammar"` // GBNF grammar definition for structured outputs
	Temperature float64 `json:"temperature"`
	MaxTokens   int     `json:"max_tokens"`
}

// InferenceResponse encapsulates generated results along with latency and token metrics.
type InferenceResponse struct {
	Content        string         `json:"content"`
	TokensPredict  int            `json:"tokens_predict"`
	TokensEval     int            `json:"tokens_eval"`
	Timings        PredictTimings `json:"timings"`
}

// LlamaEngine isolates the underlying tensor execution details from the application core.
type LlamaEngine interface {
	Predict(ctx context.Context, req InferenceRequest) (InferenceResponse, error)
	Close() error
}

// OllamaEngine connects directly to a running local Ollama instance via its HTTP API.
type OllamaEngine struct {
	client  *http.Client
	baseURL string
	model   string
}

// NewOllamaEngine initializes a new OllamaEngine targeting a specific endpoint.
func NewOllamaEngine(baseURL string) *OllamaEngine {
	if baseURL == "" {
		baseURL = "http://localhost:11434"
	}
	return &OllamaEngine{
		client: &http.Client{
			Timeout: 60 * time.Second, // Bounded timeout to prevent connection hanging
		},
		baseURL: baseURL,
		model:   "Huihui-gemma-3n-E2B-it-abliterated-i1-GGUF:Q4_K_M",
	}
}

// Predict issues a non-blocking prompt request to the running local Ollama instance.
func (e *OllamaEngine) Predict(ctx context.Context, req InferenceRequest) (InferenceResponse, error) {
	return e.processInference(ctx, req)
}

// Close is a placeholder for cleaning up resources, fulfilling the LlamaEngine interface.
func (e *OllamaEngine) Close() error {
	return nil
}

// ollamaGenerateRequest defines the API schema matching the Ollama generation endpoint.
type ollamaGenerateRequest struct {
	Model   string         `json:"model"`
	Prompt  string         `json:"prompt"`
	Stream  bool           `json:"stream"`
	Format  string         `json:"format,omitempty"`
	Options map[string]any `json:"options,omitempty"`
}

// ollamaGenerateResponse defines the structure returned by Ollama.
type ollamaGenerateResponse struct {
	Model              string `json:"model"`
	Response           string `json:"response"`
	Done               bool   `json:"done"`
	TotalDuration      int64  `json:"total_duration"`      // nanoseconds
	LoadDuration       int64  `json:"load_duration"`       // nanoseconds
	PromptEvalCount    int    `json:"prompt_eval_count"`
	PromptEvalDuration int64  `json:"prompt_eval_duration"` // nanoseconds
	EvalCount          int    `json:"eval_count"`
	EvalDuration       int64  `json:"eval_duration"`       // nanoseconds
}

// processInference issues a POST request to Ollama's HTTP generate endpoint.
func (e *OllamaEngine) processInference(ctx context.Context, req InferenceRequest) (InferenceResponse, error) {
	apiURL := fmt.Sprintf("%s/api/generate", e.baseURL)

	options := make(map[string]any)
	if req.Temperature > 0 {
		options["temperature"] = req.Temperature
	}
	if req.MaxTokens > 0 {
		options["num_predict"] = req.MaxTokens
	}

	// Build payload matching Ollama generation parameters
	// Force stream to false and set format to json as required
	payload := ollamaGenerateRequest{
		Model:   e.model,
		Prompt:  req.Prompt,
		Stream:  false,
		Format:  "json",
		Options: options,
	}

	jsonData, err := json.Marshal(payload)
	if err != nil {
		return InferenceResponse{}, fmt.Errorf("failed to marshal ollama payload: %w", err)
	}

	httpReq, err := http.NewRequestWithContext(ctx, "POST", apiURL, bytes.NewBuffer(jsonData))
	if err != nil {
		return InferenceResponse{}, fmt.Errorf("failed to create http request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")

	httpResp, err := e.client.Do(httpReq)
	if err != nil {
		return InferenceResponse{}, fmt.Errorf("ollama connection failed: %w", err)
	}
	defer httpResp.Body.Close()

	if httpResp.StatusCode != http.StatusOK {
		bodyBytes, _ := io.ReadAll(httpResp.Body)
		return InferenceResponse{}, fmt.Errorf("ollama returned HTTP error %d: %s", httpResp.StatusCode, string(bodyBytes))
	}

	var genResp ollamaGenerateResponse
	if err := json.NewDecoder(httpResp.Body).Decode(&genResp); err != nil {
		return InferenceResponse{}, fmt.Errorf("failed to decode ollama response: %w", err)
	}

	// Convert nanoseconds to milliseconds cleanly for predictable metric logging
	timings := PredictTimings{
		LoadTimeMS:       float64(genResp.LoadDuration) / 1e6,
		SampleTimeMS:     0.0, // Ollama does not report this individually
		PromptEvalTimeMS: float64(genResp.PromptEvalDuration) / 1e6,
		PredictTimeMS:    float64(genResp.EvalDuration) / 1e6,
	}

	return InferenceResponse{
		Content:       genResp.Response,
		TokensPredict: genResp.EvalCount,
		TokensEval:    genResp.PromptEvalCount,
		Timings:       timings,
	}, nil
}

// Ensure OllamaEngine implements the interface
var _ LlamaEngine = (*OllamaEngine)(nil)

// MockErrors definitions for testing edge cases
var (
	ErrContextExceeded  = errors.New("engine context window exceeded limit")
	ErrWeightLockFailed = errors.New("mlock: failed to pin weights into physical ram")
)

package core

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"
)

func TestOllamaEngine_PredictSuccess(t *testing.T) {
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	expectedResponseContent := `{"category":"financial","alert":true}`

	// Create mock Ollama HTTP server
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Verify request details
		if r.Method != "POST" {
			t.Errorf("expected POST request, got %s", r.Method)
		}
		if r.URL.Path != "/api/generate" {
			t.Errorf("expected /api/generate path, got %s", r.URL.Path)
		}
		if r.Header.Get("Content-Type") != "application/json" {
			t.Errorf("expected Content-Type application/json, got %s", r.Header.Get("Content-Type"))
		}

		var reqBody ollamaGenerateRequest
		if err := json.NewDecoder(r.Body).Decode(&reqBody); err != nil {
			t.Fatalf("failed to decode request body: %v", err)
		}

		// Verify structural configuration properties are forced correctly
		if reqBody.Model != "Huihui-gemma-3n-E2B-it-abliterated-i1-GGUF:Q4_K_M" {
			t.Errorf("expected model Huihui-gemma-3n-E2B-it-abliterated-i1-GGUF:Q4_K_M, got %s", reqBody.Model)
		}
		if reqBody.Stream != false {
			t.Errorf("expected stream false, got %t", reqBody.Stream)
		}
		if reqBody.Format != "json" {
			t.Errorf("expected format json, got %s", reqBody.Format)
		}

		// Respond with simulated Ollama response payload (nanoseconds)
		resp := ollamaGenerateResponse{
			Model:              reqBody.Model,
			Response:           expectedResponseContent,
			Done:               true,
			TotalDuration:      1500 * 1e6, // 1500 ms
			LoadDuration:       100 * 1e6,  // 100 ms
			PromptEvalCount:    40,
			PromptEvalDuration: 300 * 1e6,  // 300 ms
			EvalCount:          120,
			EvalDuration:       1100 * 1e6, // 1100 ms
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	engine := NewOllamaEngine(server.URL)
	defer engine.Close()

	req := InferenceRequest{
		Prompt:      "Analyze latest ledger anomalies.",
		Temperature: 0.1,
		MaxTokens:   64,
	}

	res, err := engine.Predict(ctx, req)
	if err != nil {
		t.Fatalf("Predict returned unexpected error: %v", err)
	}

	if res.Content != expectedResponseContent {
		t.Errorf("expected response Content '%s', got '%s'", expectedResponseContent, res.Content)
	}
	if res.TokensPredict != 120 {
		t.Errorf("expected TokensPredict 120, got %d", res.TokensPredict)
	}
	if res.TokensEval != 40 {
		t.Errorf("expected TokensEval 40, got %d", res.TokensEval)
	}

	// Verify duration nanosecond-to-millisecond conversion correctness
	if res.Timings.LoadTimeMS != 100.0 {
		t.Errorf("expected LoadTimeMS 100.0, got %.2f", res.Timings.LoadTimeMS)
	}
	if res.Timings.PromptEvalTimeMS != 300.0 {
		t.Errorf("expected PromptEvalTimeMS 300.0, got %.2f", res.Timings.PromptEvalTimeMS)
	}
	if res.Timings.PredictTimeMS != 1100.0 {
		t.Errorf("expected PredictTimeMS 1100.0, got %.2f", res.Timings.PredictTimeMS)
	}
}

func TestOllamaEngine_PredictFailure(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusInternalServerError)
		_, _ = w.Write([]byte("internal model load failure"))
	}))
	defer server.Close()

	engine := NewOllamaEngine(server.URL)
	defer engine.Close()

	_, err := engine.Predict(context.Background(), InferenceRequest{Prompt: "test"})
	if err == nil {
		t.Fatal("expected error from failed HTTP status, got nil")
	}
}

