package core

import (
	"encoding/json"
	"io/fs"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

// Asset represents a single media file tracked for social automation publishing.
type Asset struct {
	Filename string    `json:"filename"`
	Path     string    `json:"path"`
	Type     string    `json:"type"`   // "image" or "video"
	Status   string    `json:"status"` // "pending" or "deployed"
	AddedAt  time.Time `json:"added_at"`
}

// TrackerData stores the state history of media scans.
type TrackerData struct {
	Assets        map[string]Asset `json:"assets"`
	LastExecution time.Time        `json:"last_execution"`
}

// StateTracker manages atomic loading and saving of the state tracking JSON database.
type StateTracker struct {
	mu        sync.RWMutex
	statePath string
}

// NewStateTracker instantiates a StateTracker managing a specific file path.
func NewStateTracker(statePath string) *StateTracker {
	return &StateTracker{
		statePath: statePath,
	}
}

// Load loads the tracker state from disk, initializing values if the file is missing.
func (s *StateTracker) Load() (*TrackerData, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	data, err := os.ReadFile(s.statePath)
	if err != nil {
		if os.IsNotExist(err) {
			// Initialize fresh empty state
			return &TrackerData{
				Assets:        make(map[string]Asset),
				LastExecution: time.Time{},
			}, nil
		}
		return nil, err
	}

	var state TrackerData
	if err := json.Unmarshal(data, &state); err != nil {
		return nil, err
	}

	if state.Assets == nil {
		state.Assets = make(map[string]Asset)
	}

	return &state, nil
}

// Save atomically writes tracker data to the target JSON file.
func (s *StateTracker) Save(data *TrackerData) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	jsonData, err := json.MarshalIndent(data, "", "  ")
	if err != nil {
		return err
	}

	// Write to temporary file first for atomic transaction safety
	tmpPath := s.statePath + ".tmp"
	if err := os.WriteFile(tmpPath, jsonData, 0644); err != nil {
		return err
	}

	return os.Rename(tmpPath, s.statePath)
}

// ScanDirectory searches a target content folder for media files, adding new assets as pending.
func (s *StateTracker) ScanDirectory(dirPath string) ([]Asset, error) {
	// Load current state to compare
	state, err := s.Load()
	if err != nil {
		return nil, err
	}

	var scanned []Asset

	// Read directory
	err = filepath.WalkDir(dirPath, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			return nil
		}

		ext := strings.ToLower(filepath.Ext(path))
		var mediaType string

		switch ext {
		case ".jpg", ".jpeg", ".png":
			mediaType = "image"
		case ".mp4":
			mediaType = "video"
		default:
			return nil // Skip non-media formats
		}

		filename := d.Name()
		scanned = append(scanned, Asset{
			Filename: filename,
			Path:     path,
			Type:     mediaType,
		})
		return nil
	})

	if err != nil && !os.IsNotExist(err) {
		return nil, err
	}

	// Update state map with newly found assets
	stateChanged := false
	for _, asset := range scanned {
		if _, exists := state.Assets[asset.Filename]; !exists {
			asset.Status = "pending"
			asset.AddedAt = time.Now()
			state.Assets[asset.Filename] = asset
			stateChanged = true
		}
	}

	if stateChanged {
		if err := s.Save(state); err != nil {
			return nil, err
		}
	}

	// Construct active list of pending assets to return
	var pendingList []Asset
	for _, asset := range state.Assets {
		if asset.Status == "pending" {
			pendingList = append(pendingList, asset)
		}
	}

	return pendingList, nil
}

package integrations

import (
	"context"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"net/url"
	"time"
)

// InstagramClient handles requests targeting Meta's Graph API endpoints.
type InstagramClient struct {
	client            *http.Client
	encryptedToken    string
	businessAccountID string
}

// NewInstagramClient registers security parameters and instantiates a standard http client.
func NewInstagramClient(encryptedToken string, businessAccountID string) *InstagramClient {
	return &InstagramClient{
		client: &http.Client{
			Timeout: 30 * time.Second,
		},
		encryptedToken:    encryptedToken,
		businessAccountID: businessAccountID,
	}
}

// decryptToken decodes the base64-encrypted long-lived access token.
func (c *InstagramClient) decryptToken() (string, error) {
	decoded, err := base64.StdEncoding.DecodeString(c.encryptedToken)
	if err != nil {
		return "", fmt.Errorf("failed to decrypt access token payload: %w", err)
	}
	return string(decoded), nil
}

// Publish coordinates the 3-step execution dance to publish an asset to Instagram Business Profile.
func (c *InstagramClient) Publish(ctx context.Context, mediaURL string, mediaType string, caption string) (string, error) {
	token, err := c.decryptToken()
	if err != nil {
		return "", err
	}

	slog.Info("initiating instagram publishing dance",
		"media_type", mediaType,
		"media_url", mediaURL,
		"ig_user_id", c.businessAccountID,
	)

	// Step 1: Create media container
	containerID, err := c.CreateMediaContainer(ctx, token, mediaURL, mediaType, caption)
	if err != nil {
		return "", fmt.Errorf("step 1 failed (container creation): %w", err)
	}

	slog.Info("media container created successfully",
		"container_id", containerID,
	)

	// Step 2: Poll container status
	err = c.PollContainerStatus(ctx, token, containerID)
	if err != nil {
		return "", fmt.Errorf("step 2 failed (status polling): %w", err)
	}

	slog.Info("media container status returned FINISHED",
		"container_id", containerID,
	)

	// Step 3: Publish container
	postID, err := c.PublishMedia(ctx, token, containerID)
	if err != nil {
		return "", fmt.Errorf("step 3 failed (final publish): %w", err)
	}

	slog.Info("post published successfully and is now live",
		"post_id", postID,
	)

	return postID, nil
}

// CreateMediaContainer issues a POST to /media registering media assets.
func (c *InstagramClient) CreateMediaContainer(ctx context.Context, token string, mediaURL string, mediaType string, caption string) (string, error) {
	apiURL := fmt.Sprintf("https://graph.facebook.com/v22.0/%s/media", c.businessAccountID)

	form := url.Values{}
	form.Set("access_token", token)
	form.Set("caption", caption)

	if mediaType == "video" {
		form.Set("video_url", mediaURL)
		form.Set("media_type", "VIDEO")
	} else {
		form.Set("image_url", mediaURL)
	}

	req, err := http.NewRequestWithContext(ctx, "POST", apiURL, io.NopCloser(url.Values(form).Encode()))
	if err != nil {
		return "", err
	}
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")

	resp, err := c.client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	bodyBytes, _ := io.ReadAll(resp.Body)
	if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusCreated {
		return "", fmt.Errorf("http error %d: %s", resp.StatusCode, string(bodyBytes))
	}

	var res struct {
		ID string `json:"id"`
	}
	if err := json.Unmarshal(bodyBytes, &res); err != nil {
		return "", err
	}

	if res.ID == "" {
		return "", errors.New("empty container ID returned from meta api")
	}

	return res.ID, nil
}

// PollContainerStatus blocks until the media container returns as "FINISHED".
func (c *InstagramClient) PollContainerStatus(ctx context.Context, token string, containerID string) error {
	apiURL := fmt.Sprintf("https://graph.facebook.com/v22.0/%s", containerID)

	ticker := time.NewTicker(5 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-ticker.C:
			reqURL := fmt.Sprintf("%s?fields=status_code&access_token=%s", apiURL, url.QueryEscape(token))
			req, err := http.NewRequestWithContext(ctx, "GET", reqURL, nil)
			if err != nil {
				return err
			}

			resp, err := c.client.Do(req)
			if err != nil {
				slog.Warn("instagram status polling connection transient error", "error", err)
				continue
			}

			bodyBytes, _ := io.ReadAll(resp.Body)
			resp.Body.Close()

			if resp.StatusCode != http.StatusOK {
				return fmt.Errorf("polling status http error %d: %s", resp.StatusCode, string(bodyBytes))
			}

			var status struct {
				StatusCode string `json:"status_code"`
				Error      string `json:"error"`
			}
			if err := json.Unmarshal(bodyBytes, &status); err != nil {
				return err
			}

			switch status.StatusCode {
			case "FINISHED":
				return nil
			case "ERROR":
				return fmt.Errorf("meta container compilation failed: %s", status.Error)
			case "IN_PROGRESS":
				slog.Debug("container is still compiling, waiting...", "container_id", containerID)
			default:
				slog.Debug("unknown container state, waiting...", "status_code", status.StatusCode, "container_id", containerID)
			}
		}
	}
}

// PublishMedia issues a POST to /media_publish to take the post live.
func (c *InstagramClient) PublishMedia(ctx context.Context, token string, containerID string) (string, error) {
	apiURL := fmt.Sprintf("https://graph.facebook.com/v22.0/%s/media_publish", c.businessAccountID)

	form := url.Values{}
	form.Set("access_token", token)
	form.Set("creation_id", containerID)

	req, err := http.NewRequestWithContext(ctx, "POST", apiURL, io.NopCloser(url.Values(form).Encode()))
	if err != nil {
		return "", err
	}
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")

	resp, err := c.client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	bodyBytes, _ := io.ReadAll(resp.Body)
	if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusCreated {
		return "", fmt.Errorf("http error %d: %s", resp.StatusCode, string(bodyBytes))
	}

	var res struct {
		ID string `json:"id"`
	}
	if err := json.Unmarshal(bodyBytes, &res); err != nil {
		return "", err
	}

	if res.ID == "" {
		return "", errors.New("empty post ID returned from meta api_publish")
	}

	return res.ID, nil
}

package core

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"sync"
	"time"
)

// InstagramPublisher interface abstracts the publishing method for scheduling dependency injection.
type InstagramPublisher interface {
	Publish(ctx context.Context, mediaURL string, mediaType string, caption string) (string, error)
}

// Scheduler manages the background interval execution loops for social media automation.
type Scheduler struct {
	tracker      *StateTracker
	igClient     InstagramPublisher
	botPool      *BotPool
	contentDir   string
	interval     time.Duration
	shutdownChan chan struct{}
	wg           sync.WaitGroup
}

// NewScheduler instantiates a new Scheduler.
func NewScheduler(tracker *StateTracker, igClient InstagramPublisher, botPool *BotPool, contentDir string, interval time.Duration) *Scheduler {
	return &Scheduler{
		tracker:      tracker,
		igClient:     igClient,
		botPool:      botPool,
		contentDir:   contentDir,
		interval:     interval,
		shutdownChan: make(chan struct{}),
	}
}

// Start spawns the background execution ticker.
func (s *Scheduler) Start(ctx context.Context) {
	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		ticker := time.NewTicker(s.interval)
		defer ticker.Stop()

		slog.Info("instaminion background scheduler engine started successfully",
			"interval_seconds", s.interval.Seconds(),
			"content_directory", s.contentDir,
		)

		// Run immediate execution tick on start
		s.executeScheduledBlock(ctx)

		for {
			select {
			case <-ctx.Done():
				slog.Info("scheduler background execution loop cancelled by system context")
				return
			case <-s.shutdownChan:
				slog.Info("scheduler background execution loop shutting down")
				return
			case <-ticker.C:
				s.executeScheduledBlock(ctx)
			}
		}
	}()
}

// Stop initiates a graceful shutdown of the scheduling ticker.
func (s *Scheduler) Stop() {
	close(s.shutdownChan)
	s.wg.Wait()
}

// executeScheduledBlock implements the core orchestrator logic for scheduling ticks.
func (s *Scheduler) executeScheduledBlock(ctx context.Context) {
	slog.Info("executing scheduled pipeline block scan")

	// 1. Scan directory for pending files
	pending, err := s.tracker.ScanDirectory(s.contentDir)
	if err != nil {
		slog.Error("scheduler directory scan execution failed", "error", err)
		return
	}

	if len(pending) == 0 {
		slog.Info("no pending assets found to publish in this block")
		return
	}

	// Extract the first pending asset
	asset := pending[0]
	slog.Info("extracted pending asset for scheduling processing",
		"filename", asset.Filename,
		"type", asset.Type,
	)

	// 2. Formulate caption generation request targeting the 'instagram_creator' profile
	promptText := fmt.Sprintf("Generate a highly engaging Instagram caption with trending hashtags for a media asset named: %s. Emphasize visual details.", asset.Filename)

	// Format task wrapper to route to instagram_creator bot
	payload := PayloadWrapper{
		BotID:   "instagram_creator",
		Content: promptText,
	}
	payloadBytes, err := json.Marshal(payload)
	if err != nil {
		slog.Error("failed to marshal caption task payload", "error", err)
		return
	}

	respChan := make(chan TaskResult, 1)
	task := Task{
		ID:           fmt.Sprintf("schedule-%s-%d", asset.Filename, time.Now().Unix()),
		Payload:      string(payloadBytes),
		ResponseChan: respChan,
	}

	// Submit task to BotPool (non-blocking)
	err = s.botPool.Route(ctx, task)
	if err != nil {
		slog.Error("failed to route caption generation task to bot orchestrator",
			"task_id", task.ID,
			"error", err,
		)
		return
	}

	// Wait for caption generation with timeout protection
	var caption string
	select {
	case <-ctx.Done():
		slog.Error("context exceeded during caption generation stage", "error", ctx.Err())
		return
	case res := <-respChan:
		if res.Error != nil {
			slog.Error("bot caption generation task failed",
				"task_id", res.ID,
				"error", res.Error.Error(),
			)
			return
		}

		// Parse the output context
		// Gemma might output a raw JSON matching the bot GBNF format
		var parsed struct {
			Caption string `json:"caption"`
		}
		if jsonErr := json.Unmarshal([]byte(res.Response.Content), &parsed); jsonErr == nil && parsed.Caption != "" {
			caption = parsed.Caption
		} else {
			// Fallback to raw response content if JSON parse fails
			caption = res.Response.Content
		}
	}

	slog.Info("successfully generated post caption",
		"filename", asset.Filename,
		"caption_preview", caption,
	)

	// 3. Publish final output to Instagram Business Account
	// Note: Meta requires a public HTTP URL to download images/videos.
	// For local test paths, we pass the local absolute path or compile a mock endpoint.
	postID, err := s.igClient.Publish(ctx, asset.Path, asset.Type, caption)
	if err != nil {
		slog.Error("instagram media publication failed",
			"filename", asset.Filename,
			"error", err,
		)
		return
	}

	slog.Info("asset successfully published live to profile",
		"filename", asset.Filename,
		"post_id", postID,
	)

	// 4. Update state tracker status to deployed
	state, err := s.tracker.Load()
	if err != nil {
		slog.Error("failed to load state to update asset status", "error", err)
		return
	}

	if a, exists := state.Assets[asset.Filename]; exists {
		a.Status = "deployed"
		state.Assets[asset.Filename] = a
		state.LastExecution = time.Now()

		if saveErr := s.tracker.Save(state); saveErr != nil {
			slog.Error("failed to save state after successful deployment", "error", saveErr)
		}
	}
}

package core

import (
	"os"
	"path/filepath"
	"testing"
)

func TestStateTracker_ScanAndSave(t *testing.T) {
	tmpDir, err := os.MkdirTemp("", "ingest-test")
	if err != nil {
		t.Fatalf("failed to create temp dir: %v", err)
	}
	defer os.RemoveAll(tmpDir)

	statePath := filepath.Join(tmpDir, "state.json")
	contentDir := filepath.Join(tmpDir, "content")
	if err := os.Mkdir(contentDir, 0755); err != nil {
		t.Fatalf("failed to create content dir: %v", err)
	}

	// Create dummy media files
	imgFile := filepath.Join(contentDir, "pic.png")
	if err := os.WriteFile(imgFile, []byte("image-data"), 0644); err != nil {
		t.Fatalf("failed to write img file: %v", err)
	}

	vidFile := filepath.Join(contentDir, "movie.mp4")
	if err := os.WriteFile(vidFile, []byte("video-data"), 0644); err != nil {
		t.Fatalf("failed to write video file: %v", err)
	}

	txtFile := filepath.Join(contentDir, "doc.txt")
	if err := os.WriteFile(txtFile, []byte("text-data"), 0644); err != nil {
		t.Fatalf("failed to write txt file: %v", err)
	}

	tracker := NewStateTracker(statePath)

	// First scan: should discover new png and mp4 media files, skipping txt
	pending, err := tracker.ScanDirectory(contentDir)
	if err != nil {
		t.Fatalf("ScanDirectory failed: %v", err)
	}

	if len(pending) != 2 {
		t.Errorf("expected 2 pending media files, got %d", len(pending))
	}

	var hasPng, hasMp4 bool
	for _, asset := range pending {
		if asset.Filename == "pic.png" {
			hasPng = true
			if asset.Type != "image" {
				t.Errorf("expected type image for pic.png, got %s", asset.Type)
			}
		}
		if asset.Filename == "movie.mp4" {
			hasMp4 = true
			if asset.Type != "video" {
				t.Errorf("expected type video for movie.mp4, got %s", asset.Type)
			}
		}
	}

	if !hasPng || !hasMp4 {
		t.Errorf("missing scanned png or mp4 files in results")
	}

	// Verify state file exists and matches values
	state, err := tracker.Load()
	if err != nil {
		t.Fatalf("failed to load state tracker: %v", err)
	}

	if len(state.Assets) != 2 {
		t.Errorf("expected 2 tracked assets in state.json, got %d", len(state.Assets))
	}

	// Second scan: no new media files added, so returned list should still show 2 pending
	pending2, err := tracker.ScanDirectory(contentDir)
	if err != nil {
		t.Fatalf("second ScanDirectory failed: %v", err)
	}
	if len(pending2) != 2 {
		t.Errorf("expected still 2 pending assets, got %d", len(pending2))
	}
}

