package integrations

import (
	"context"
	"encoding/base64"
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"net/url"
	"strings"
	"sync/atomic"
	"testing"
	"time"
)

func TestInstagramClient_PublishSuccess(t *testing.T) {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	rawToken := "long-lived-meta-access-token"
	encryptedToken := base64.StdEncoding.EncodeToString([]byte(rawToken))
	igUserID := "17841401234567890"

	var pollCount int32

	// Setup local mock Meta Graph API server
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")

		// 1. Step 1: Create Container
		if r.Method == "POST" && strings.HasSuffix(r.URL.Path, "/media") {
			bodyBytes, _ := io.ReadAll(r.Body)
			values, err := url.ParseQuery(string(bodyBytes))
			if err != nil {
				t.Fatalf("failed to parse form values: %v", err)
			}

			if values.Get("access_token") != rawToken {
				t.Errorf("expected access_token %s, got %s", rawToken, values.Get("access_token"))
			}

			if values.Get("caption") != "Verify Meta API v22.0" {
				t.Errorf("expected caption, got %s", values.Get("caption"))
			}

			if values.Get("image_url") != "http://example.com/asset.jpg" {
				t.Errorf("expected image_url, got %s", values.Get("image_url"))
			}

			w.WriteHeader(http.StatusCreated)
			_, _ = w.Write([]byte(`{"id":"container_9988"}`))
			return
		}

		// 2. Step 2: Poll Container Status
		if r.Method == "GET" && strings.HasSuffix(r.URL.Path, "/container_9988") {
			if r.URL.Query().Get("access_token") != rawToken {
				t.Errorf("expected access_token in query, got %s", r.URL.Query().Get("access_token"))
			}

			count := atomic.AddInt32(&pollCount, 1)
			if count == 1 {
				// First check: in progress compiling
				_, _ = w.Write([]byte(`{"status_code":"IN_PROGRESS"}`))
				return
			}

			// Second check: finished processing
			_, _ = w.Write([]byte(`{"status_code":"FINISHED"}`))
			return
		}

		// 3. Step 3: Final Publish
		if r.Method == "POST" && strings.HasSuffix(r.URL.Path, "/media_publish") {
			bodyBytes, _ := io.ReadAll(r.Body)
			values, _ := url.ParseQuery(string(bodyBytes))

			if values.Get("access_token") != rawToken {
				t.Errorf("expected access_token %s, got %s", rawToken, values.Get("access_token"))
			}

			if values.Get("creation_id") != "container_9988" {
				t.Errorf("expected creation_id container_9988, got %s", values.Get("creation_id"))
			}

			w.WriteHeader(http.StatusOK)
			_, _ = w.Write([]byte(`{"id":"post_8877"}`))
			return
		}

		w.WriteHeader(http.StatusBadRequest)
		_, _ = w.Write([]byte(`{"error":"unexpected API request"}`))
	}))
	defer server.Close()

	client := NewInstagramClient(encryptedToken, igUserID)
	// Intercept transport on http.Client
	client.client.Transport = &mockTransport{
		serverURL: server.URL,
	}

	postID, err := client.Publish(ctx, "http://example.com/asset.jpg", "image", "Verify Meta API v22.0")
	if err != nil {
		t.Fatalf("Publish failed: %v", err)
	}

	if postID != "post_8877" {
		t.Errorf("expected postID 'post_8877', got '%s'", postID)
	}

	if atomic.LoadInt32(&pollCount) != 2 {
		t.Errorf("expected exactly 2 status poll iterations, got %d", atomic.LoadInt32(&pollCount))
	}
}

// Helper structures for transport hijacking in unit tests
type mockTransport struct {
	serverURL string
}

func (m *mockTransport) RoundTrip(req *http.Request) (*http.Response, error) {
	// Re-route graph.facebook.com to our local test server URL
	originalURL := req.URL.String()
	mockedURL := strings.Replace(originalURL, "https://graph.facebook.com", m.serverURL, 1)

	newURL, err := url.Parse(mockedURL)
	if err != nil {
		return nil, err
	}
	req.URL = newURL

	// Execute request using default transport
	return http.DefaultTransport.RoundTrip(req)
}

package core

import (
	"context"
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
	"time"
)

type mockInstagramPublisher struct {
	LastURL      string
	LastType     string
	LastCaption  string
	PublishCount int
}

func (m *mockInstagramPublisher) Publish(ctx context.Context, mediaURL string, mediaType string, caption string) (string, error) {
	m.LastURL = mediaURL
	m.LastType = mediaType
	m.LastCaption = caption
	m.PublishCount++
	return "mock-post-id-123", nil
}

func TestScheduler_ExecutionBlock(t *testing.T) {
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	tmpDir, err := os.MkdirTemp("", "scheduler-test")
	if err != nil {
		t.Fatalf("failed to create temp dir: %v", err)
	}
	defer os.RemoveAll(tmpDir)

	statePath := filepath.Join(tmpDir, "state.json")
	contentDir := filepath.Join(tmpDir, "content")
	_ = os.Mkdir(contentDir, 0755)

	// Create a single pending image asset
	imgFile := filepath.Join(contentDir, "photo.jpg")
	_ = os.WriteFile(imgFile, []byte("photo-data"), 0644)

	tracker := NewStateTracker(statePath)
	publisher := &mockInstagramPublisher{}

	// Setup Engine and WorkerPool for caption generation
	engine := NewMockLlamaEngine()
	wp := NewWorkerPool(engine, 1, 5)
	wp.Start(ctx)
	defer wp.Stop()

	bp := NewBotPool(wp)

	// Register a mock instagram_creator bot profile
	// Let's make it load a real mock grammar file to succeed in routing
	grammarPath := filepath.Join(tmpDir, "creator.gbnf")
	_ = os.WriteFile(grammarPath, []byte("root ::= [a-z]+"), 0644)

	err = bp.RegisterProfile(BotProfile{
		ID:           "instagram_creator",
		Name:         "Instagram Creator Bot",
		SystemPrompt: "You are a professional social media content creator.",
		GrammarPath:  grammarPath,
	})
	if err != nil {
		t.Fatalf("failed to register bot profile: %v", err)
	}

	scheduler := NewScheduler(tracker, publisher, bp, contentDir, 50*time.Millisecond)

	// Force run a single scheduled execution block manually to assert synchronous execution flow
	scheduler.executeScheduledBlock(ctx)

	// Assertions
	if publisher.PublishCount != 1 {
		t.Errorf("expected exactly 1 publication call, got %d", publisher.PublishCount)
	}
	if publisher.LastURL != imgFile {
		t.Errorf("expected published URL to match path %s, got %s", imgFile, publisher.LastURL)
	}
	if publisher.LastType != "image" {
		t.Errorf("expected type image, got %s", publisher.LastType)
	}

	// Verify caption was populated (should contain mock json generated by the MockLlamaEngine)
	var expectedMockJSON struct {
		Category  string `json:"category"`
		Urgency   string `json:"urgency"`
		Sentiment string `json:"sentiment"`
		Summary   string `json:"summary"`
	}
	if err := json.Unmarshal([]byte(publisher.LastCaption), &expectedMockJSON); err != nil {
		t.Errorf("expected caption to match structured json generated from mock engine, got error: %v (caption: %s)", err, publisher.LastCaption)
	}

	// Load state and verify asset status is updated to deployed
	state, err := tracker.Load()
	if err != nil {
		t.Fatalf("failed to load state tracker: %v", err)
	}

	asset, exists := state.Assets["photo.jpg"]
	if !exists {
		t.Fatal("expected photo.jpg to be tracked in state")
	}

	if asset.Status != "deployed" {
		t.Errorf("expected asset status deployed, got %s", asset.Status)
	}

	if state.LastExecution.IsZero() {
		t.Error("expected LastExecution timestamp to be updated")
	}
}

